namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private readonly List<Notification> _notifications;
    private int _nextId;

    public NotificationService()
    {
        _notifications =
        [
            new(1, "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-30)),
            new(2, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-20)),
            new(3, "New comment on your post.", DateTime.UtcNow.AddMinutes(-10)),
        ];
        _nextId = 4;
    }

    /// <summary>Returns all notifications available at the time of the call.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
        => Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());

    /// <summary>Returns only notifications that arrived after <paramref name="since"/>.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
        => Task.FromResult(
            _notifications
                .Where(n => n.Timestamp > since)
                .OrderByDescending(n => n.Timestamp)
                .ToList());

    /// <summary>
    /// Simulates an external system pushing new notifications.
    /// Called internally to keep the fake data growing.
    /// </summary>
    public Notification AddRandom()
    {
        string[] samples =
        [
            "Server deployment completed.",
            "You have a new follower.",
            "Disk usage exceeded 80%.",
            "Backup finished successfully.",
            "A scheduled task failed — check logs.",
            "Your subscription will renew soon.",
        ];

        var msg = samples[Random.Shared.Next(samples.Length)];
        var notification = new Notification(_nextId++, msg, DateTime.UtcNow);
        _notifications.Add(notification);
        return notification;
    }
}

@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@implements IDisposable
@inject NotificationsApp.Services.NotificationService NotificationSvc

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationsApp.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private DateTime _lastCheck;

    // Runs during both prerender AND interactive init.
    // On prerender it seeds the list so the HTML ships with data.
    // On the interactive init the framework reuses the already-serialized
    // component state, so the service is NOT called a second time.
    protected override async Task OnInitializedAsync()
    {
        _notifications = await NotificationSvc.GetNotificationsAsync();
        _lastCheck = _notifications.Count > 0
            ? _notifications.Max(n => n.Timestamp)
            : DateTime.UtcNow;
    }

    // Only fires once the circuit is live — never during static SSR.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            // Simulate new data arriving from time to time
            if (Random.Shared.Next(3) == 0)
            {
                NotificationSvc.AddRandom();
            }

            var newer = await NotificationSvc.GetNotificationsSinceAsync(_lastCheck);
            if (newer.Count > 0)
            {
                _notifications.InsertRange(0, newer);
                _lastCheck = newer.Max(n => n.Timestamp);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

